from elasticsearch import Elasticsearch
import logging

# Initialize Elasticsearch client
es = Elasticsearch([{'host': 'localhost', 'port': 9200}])

# Initialize logger
logger = logging.getLogger(__name__)
handler = logging.StreamHandler()
formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')
handler.setFormatter(formatter)
logger.addHandler(handler)
logger.setLevel(logging.INFO)

# Indexing function
def index_document(doc_type, doc_id, body):
    res = es.index(index='logs', doc_type=doc_type, id=doc_id, body=body)
    return res['result']

# Search function
def search(query):
    res = es.search(index='logs', body={"query": {"match": {"_all": query}}})
    return res['hits']['hits']

# Logging example
logger.info("This is an info log message")

# Indexing example
index_document('example', 1, {'title': 'Test Document', 'content': 'This is a test document.'})

# Search example
results = search('test')
for result in results:
    print(result['_source'])